import{_ as o,c as e,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Ultrawork模式: 一键激活全部功能 | oh-my-opencode","description":"学习 oh-my-opencode 的 Ultrawork 模式与核心特性，包括 ultrawork 关键词使用方法、激活行为变化、并行探索机制、强制完成验证及代理协作等，快速激活所有高级功能。","frontmatter":{"title":"Ultrawork模式: 一键激活全部功能 | oh-my-opencode","sidebarTitle":"一键激活全部功能","subtitle":"Ultrawork模式: 一键激活全部功能","description":"学习 oh-my-opencode 的 Ultrawork 模式与核心特性，包括 ultrawork 关键词使用方法、激活行为变化、并行探索机制、强制完成验证及代理协作等，快速激活所有高级功能。","tags":["ultrawork","后台任务","代理协作"],"prerequisite":["start-installation","start-sisyphus-orchestrator"],"order":30},"headers":[],"relativePath":"zh/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md","filePath":"zh/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"}'),l={name:"zh/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"};function d(i,t,s,n,c,u){return a(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="ultrawork模式-一键激活全部功能" tabindex="-1">Ultrawork模式：一键激活全部功能 <a class="header-anchor" href="#ultrawork模式-一键激活全部功能" aria-label="Permalink to &quot;Ultrawork模式：一键激活全部功能&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>用一句话激活 oh-my-opencode 的全部高级功能</li><li>让多个 AI 代理像真实团队一样并行工作</li><li>避免手动配置多个代理和后台任务</li><li>理解 Ultrawork 模式的设计哲学和最佳实践</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你可能在开发过程中遇到过这些情况：</p><ul><li><strong>功能太多不知道怎么用</strong>：有 10 个专业代理、后台任务、LSP 工具，但不知道如何快速激活</li><li><strong>需要手动配置</strong>：每次复杂任务都要手动指定代理、后台并发等配置</li><li><strong>代理协作不高效</strong>：串行调用代理，浪费时间和成本</li><li><strong>任务中途卡住</strong>：代理没有足够的动力和约束去完成任务</li></ul><p>这些都在影响你发挥 oh-my-opencode 的真正威力。</p><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><strong>Ultrawork 模式</strong>是 oh-my-opencode 的&quot;一键全员激活&quot;机制。</p><div class="info custom-block"><p class="custom-block-title">什么是 Ultrawork 模式？</p><p>Ultrawork 模式是一个关键词触发的特殊工作模式。当你在提示词中包含 <code>ultrawork</code> 或缩写 <code>ulw</code> 时，系统会自动激活所有高级功能：并行后台任务、深度探索、强制完成、多代理协作等。</p></div><h3 id="设计哲学" tabindex="-1">设计哲学 <a class="header-anchor" href="#设计哲学" aria-label="Permalink to &quot;设计哲学&quot;">​</a></h3><p>Ultrawork 模式基于以下核心原则（来自 <a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer">Ultrawork Manifesto</a>）：</p><table tabindex="0"><thead><tr><th>原则</th><th>说明</th></tr></thead><tbody><tr><td><strong>人类干预是失败信号</strong></td><td>如果需要你不断修正 AI 的输出，说明系统设计有问题</td></tr><tr><td><strong>不可区分的代码</strong></td><td>AI 写的代码应该和资深工程师写的没有区别</td></tr><tr><td><strong>最小化认知负担</strong></td><td>你只需要说&quot;做什么&quot;，代理负责&quot;怎么做&quot;</td></tr><tr><td><strong>可预测、持续、可委托</strong></td><td>代理应该像编译器一样稳定可靠</td></tr></tbody></table><h3 id="激活机制" tabindex="-1">激活机制 <a class="header-anchor" href="#激活机制" aria-label="Permalink to &quot;激活机制&quot;">​</a></h3><p>当系统检测到 <code>ultrawork</code> 或 <code>ulw</code> 关键词时：</p><ol><li><strong>设置最大精度模式</strong>：<code>message.variant = &quot;max&quot;</code></li><li><strong>显示 Toast 通知</strong>：&quot;Ultrawork Mode Activated - Maximum precision engaged. All agents at your disposal.&quot;</li><li><strong>注入完整指令</strong>：向代理注入 200+ 行的 ULTRAWORK 指令，包括： <ul><li>强制 100% 确定才开始实现</li><li>要求并行使用后台任务</li><li>强制使用 Category + Skills 系统</li><li>强制完成验证（TDD 工作流）</li><li>禁止任何&quot;我做不到&quot;的借口</li></ul></li></ol><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-触发-ultrawork-模式" tabindex="-1">第 1 步：触发 Ultrawork 模式 <a class="header-anchor" href="#第-1-步-触发-ultrawork-模式" aria-label="Permalink to &quot;第 1 步：触发 Ultrawork 模式&quot;">​</a></h3><p>在 OpenCode 中输入包含 <code>ultrawork</code> 或 <code>ulw</code> 关键词的提示词：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ultrawork 开发一个 REST API</span></span></code></pre></div><p>或者更简洁：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ulw 添加用户认证</span></span></code></pre></div><p><strong>你应该看到</strong>：</p><ul><li>界面弹出 Toast 通知：&quot;Ultrawork Mode Activated&quot;</li><li>代理回复以 &quot;ULTRAWORK MODE ENABLED!&quot; 开头</li></ul><h3 id="第-2-步-观察代理行为变化" tabindex="-1">第 2 步：观察代理行为变化 <a class="header-anchor" href="#第-2-步-观察代理行为变化" aria-label="Permalink to &quot;第 2 步：观察代理行为变化&quot;">​</a></h3><p>激活 Ultrawork 模式后，代理会：</p><ol><li><p><strong>并行探索代码库</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;查找现有 API 模式&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;查找测试基础设施&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;librarian&quot;, prompt=&quot;查找认证最佳实践&quot;, background=true)</span></span></code></pre></div></li><li><p><strong>调用 Plan 代理制定工作计划</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(subagent_type=&quot;plan&quot;, prompt=&quot;基于收集的上下文，制定详细计划&quot;)</span></span></code></pre></div></li><li><p><strong>使用 Category + Skills 执行任务</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(category=&quot;visual-engineering&quot;, load_skills=[&quot;frontend-ui-ux&quot;, &quot;playwright&quot;], ...)</span></span></code></pre></div></li></ol><p><strong>你应该看到</strong>：</p><ul><li>多个后台任务同时运行</li><li>代理主动调用专业代理（Oracle、Librarian、Explore）</li><li>完整的测试计划和工作分解</li><li>任务持续执行直到 100% 完成</li></ul><h3 id="第-3-步-验证任务完成" tabindex="-1">第 3 步：验证任务完成 <a class="header-anchor" href="#第-3-步-验证任务完成" aria-label="Permalink to &quot;第 3 步：验证任务完成&quot;">​</a></h3><p>代理完成后会：</p><ol><li><strong>展示验证证据</strong>：实际运行测试的输出、手动验证的描述</li><li><strong>确认所有 TODO 完成</strong>：不会提前声明完成</li><li><strong>总结工作内容</strong>：列出做了什么、为什么这样做</li></ol><p><strong>你应该看到</strong>：</p><ul><li>明确的测试结果（不是&quot;应该可以&quot;）</li><li>所有问题都已解决</li><li>没有未完成的 TODO 列表</li></ul><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>完成上述步骤后，确认：</p><ul><li>[ ] 输入 <code>ulw</code> 后看到 Toast 通知</li><li>[ ] 代理回复以 &quot;ULTRAWORK MODE ENABLED!&quot; 开头</li><li>[ ] 观察到并行后台任务运行</li><li>[ ] 代理使用 Category + Skills 系统</li><li>[ ] 任务完成后有验证证据</li></ul><p>如果任何一项未通过，检查：</p><ul><li>关键词是否正确拼写（<code>ultrawork</code> 或 <code>ulw</code>）</li><li>是否在主会话中（后台任务不会触发模式）</li><li>配置文件是否启用了相关功能</li></ul><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>使用 Ultrawork</th><th>普通模式</th></tr></thead><tbody><tr><td><strong>复杂新功能</strong></td><td>✅ 推荐（需要多代理协作）</td><td>❌ 可能不够高效</td></tr><tr><td><strong>紧急修复</strong></td><td>✅ 推荐（需要快速诊断和探索）</td><td>❌ 可能遗漏上下文</td></tr><tr><td><strong>简单修改</strong></td><td>❌ 过度（浪费资源）</td><td>✅ 更合适</td></tr><tr><td><strong>快速验证想法</strong></td><td>❌ 过度</td><td>✅ 更合适</td></tr></tbody></table><p><strong>经验法则</strong>：</p><ul><li>任务涉及多个模块或系统 → 用 <code>ulw</code></li><li>需要深入研究代码库 → 用 <code>ulw</code></li><li>需要调用多个专业代理 → 用 <code>ulw</code></li><li>单文件小改动 → 不需要 <code>ulw</code></li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">注意事项</p><p><strong>1. 不要在每个提示词中都使用 <code>ulw</code></strong></p><p>Ultrawork 模式会注入大量指令，对于简单任务来说是过度设计。只有真正需要多代理协作、并行探索、深度分析的复杂任务才使用。</p><p><strong>2. 后台任务不会触发 Ultrawork 模式</strong></p><p>关键词检测器会跳过后台会话，避免模式错误注入到子代理。Ultrawork 模式只在主会话中有效。</p><p><strong>3. 确保 Provider 配置正确</strong></p><p>Ultrawork 模式依赖多个 AI 模型并行工作。如果某些 Provider 未配置或不可用，代理可能无法调用专业代理。</p></div><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>Ultrawork 模式通过关键词触发，实现了&quot;一句话激活全部功能&quot;的设计目标：</p><ul><li><strong>简单易用</strong>：输入 <code>ulw</code> 即可激活</li><li><strong>自动协作</strong>：代理自动调用其他代理、并行执行后台任务</li><li><strong>强制完成</strong>：完整的验证机制确保 100% 完成</li><li><strong>零配置</strong>：无需手动设置代理优先级、并发限制等</li></ul><p>记住：Ultrawork 模式是为了让代理像真实团队一样工作，你只需要表达意图，代理负责执行。</p><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../../platforms/provider-setup/">Provider 配置</a></strong>。</p><p>你会学到：</p><ul><li>如何配置 Anthropic、OpenAI、Google 等多个 Provider</li><li>多模型策略如何自动降级和选择最优模型</li><li>如何测试 Provider 连接和额度使用</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>Ultrawork 设计哲学</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer"><code>docs/ultrawork-manifesto.md</code></a></td><td>1-198</td></tr><tr><td>关键词检测器 Hook</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/index.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/index.ts</code></a></td><td>12-100</td></tr><tr><td>ULTRAWORK 指令模板</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/constants.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/constants.ts</code></a></td><td>54-280</td></tr><tr><td>关键词检测逻辑</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/detector.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/detector.ts</code></a></td><td>26-53</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>KEYWORD_DETECTORS</code>：关键词检测器配置，包含 ultrawork、search、analyze 三个模式</li><li><code>CODE_BLOCK_PATTERN</code>：代码块正则表达式，用于过滤代码块中的关键词</li><li><code>INLINE_CODE_PATTERN</code>：行内代码正则表达式，用于过滤行内代码中的关键词</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>createKeywordDetectorHook()</code>：创建关键词检测器 Hook，监听 UserPromptSubmit 事件</li><li><code>detectKeywordsWithType()</code>：检测文本中的关键词并返回类型（ultrawork/search/analyze）</li><li><code>getUltraworkMessage()</code>：生成 ULTRAWORK 模式的完整指令（根据代理类型选择 Planner 或普通模式）</li><li><code>removeCodeBlocks()</code>：从文本中移除代码块，避免在代码块中误触发关键词</li></ul><p><strong>业务规则</strong>：</p><table tabindex="0"><thead><tr><th>规则ID</th><th>规则描述</th><th>标记</th></tr></thead><tbody><tr><td>BR-4.8.4-1</td><td>检测到 &quot;ultrawork&quot; 或 &quot;ulw&quot; 时激活 Ultrawork 模式</td><td>【事实】</td></tr><tr><td>BR-4.8.4-2</td><td>Ultrawork 模式设置 <code>message.variant = &quot;max&quot;</code></td><td>【事实】</td></tr><tr><td>BR-4.8.4-3</td><td>Ultrawork 模式显示 Toast 通知：&quot;Ultrawork Mode Activated&quot;</td><td>【事实】</td></tr><tr><td>BR-4.8.4-4</td><td>后台任务会话跳过关键词检测，避免模式注入</td><td>【事实】</td></tr><tr><td>BR-4.8.4-5</td><td>非主会话只允许 ultrawork 关键词，阻止其他模式注入</td><td>【事实】</td></tr></tbody></table></details>`,54)])])}const g=o(l,[["render",d]]);export{h as __pageData,g as default};
